import { useNavigate } from "react-router-dom";

function Navbar() {
  const navigate = useNavigate();

  const logout = () => {
    localStorage.removeItem("token");
    navigate("/");
  };

  return (
    <div className="navbar">
      <h3>Golf Charity</h3>
      <button onClick={logout} style={{ width: "100px" }}>Logout</button>
    </div>
  );
}

export default Navbar;
